13905   if (E != InstrElementSize.end())
13906     return E->second;
13907 
13908   // If V is not a store, we can traverse the expression tree to find loads
13909   // that feed it. The type of the loaded value may indicate a more suitable
13910   // width than V's type. We want to base the vector element size on the width
13911   // of memory operations where possible.
13912   SmallVector<std::pair<Instruction *, BasicBlock *>, 16> Worklist;
13913   SmallPtrSet<Instruction *, 16> Visited;
13914   if (auto *I = dyn_cast<Instruction>(V)) {
13915     Worklist.emplace_back(I, I->getParent());
13916     Visited.insert(I);
13917   }
13918 
13919   // Traverse the expression tree in bottom-up order looking for loads. If we
13920   // encounter an instruction we don't yet handle, we give up.
13921   auto Width = 0u;
13922   while (!Worklist.empty()) {
13923     Instruction *I;
13924     BasicBlock *Parent;
13925     std::tie(I, Parent) = Worklist.pop_back_val();
13926 
13927     // We should only be looking at scalar instructions here. If the current
13928     // instruction has a vector type, skip.
13929     auto *Ty = I->getType();
13930     if (isa<VectorType>(Ty))
13931       continue;
13932 
13933     // If the current instruction is a load, update MaxWidth to reflect the
13934     // width of the loaded value.
13935     if (isa<LoadInst, ExtractElementInst, ExtractValueInst>(I))
13936       Width = std::max<unsigned>(Width, DL->getTypeSizeInBits(Ty));
13937 
13938     // Otherwise, we need to visit the operands of the instruction. We only
13939     // handle the interesting cases from buildTree here. If an operand is an
13940     // instruction we haven't yet visited and from the same basic block as the
13941     // user or the use is a PHI node, we add it to the worklist.
13942     else if (isa<PHINode, CastInst, GetElementPtrInst, CmpInst, SelectInst,
13943                  BinaryOperator, UnaryOperator>(I)) {
13944       for (Use &U : I->operands())
13945         if (auto *J = dyn_cast<Instruction>(U.get()))
13946           if (Visited.insert(J).second &&
13947               (isa<PHINode>(I) || J->getParent() == Parent))
13948             Worklist.emplace_back(J, J->getParent());
13949     } else {
13950       break;
13951     }
13952   }
13953 
13954   // If we didn't encounter a memory access in the expression tree, or if we
13955   // gave up for some reason, just return the width of V. Otherwise, return the
13956   // maximum width we found.
13957   if (!Width) {
13958     if (auto *CI = dyn_cast<CmpInst>(V))
13959       V = CI->getOperand(0);
13960     Width = DL->getTypeSizeInBits(V->getType());
13961   }
