14293     IsProfitableToDemoteRoot = true;
14294 
14295     if (TruncNodes.empty()) {
14296       NodeIdx = VectorizableTree.size();
14297     } else {
14298       NodeIdx = *TruncNodes.begin() + 1;
14299       TruncNodes.erase(TruncNodes.begin());
14300       IsTruncRoot = true;
14301     }
14302 
14303     // If the maximum bit width we compute is less than the with of the roots'
14304     // type, we can proceed with the narrowing. Otherwise, do nothing.
14305     if (MaxBitWidth == 0 ||
14306         MaxBitWidth >=
14307             cast<IntegerType>(TreeRoot.front()->getType())->getBitWidth()) {
14308       if (UserIgnoreList)
14309         AnalyzedMinBWVals.insert(TreeRoot.begin(), TreeRoot.end());
14310       continue;
14311     }
14312 
14313     // Finally, map the values we can demote to the maximum bit with we
14314     // computed.
14315     for (Value *Scalar : ToDemote) {
14316       TreeEntry *TE = getTreeEntry(Scalar);
14317       assert(TE && "Expected vectorized scalar.");
14318       if (MinBWs.contains(TE))
14319         continue;
14320       bool IsSigned = TE->getOpcode() == Instruction::SExt ||
14321                       any_of(TE->Scalars, [&](Value *R) {
14322                         return !isKnownNonNegative(R, SimplifyQuery(*DL));
14323                       });
14324       MinBWs.try_emplace(TE, MaxBitWidth, IsSigned);
14325       const auto *I = cast<Instruction>(Scalar);
14326       auto DCIt = DemotedConsts.find(I);
14327       if (DCIt != DemotedConsts.end()) {
14328         for (unsigned Idx : DCIt->getSecond()) {
14329           // Check that all instructions operands are demoted.
14330           const TreeEntry *CTE = getOperandEntry(TE, Idx);
14331           if (all_of(TE->Scalars,
14332                      [&](Value *V) {
14333                        auto SIt = DemotedConsts.find(cast<Instruction>(V));
14334                        return SIt != DemotedConsts.end() &&
14335                               is_contained(SIt->getSecond(), Idx);
14336                      }) ||
14337               all_of(CTE->Scalars, Constant::classof))
14338             MinBWs.try_emplace(CTE, MaxBitWidth, IsSigned);
14339         }
14340       }
14341     }
14342   }
14343 }
